/**
 * URL Shortener Service
 * 
 * Provides URL shortening functionality for ad platform integrations.
 * Uses UUID-based encoding to embed UTM parameters directly in the short code,
 * eliminating the need for database lookups on redirect.
 * 
 * Short URL format: https://spotlessbinco.com/s/{encoded_uuid}
 * 
 * The UUID encodes:
 * - Platform (facebook/tiktok/google) - 2 bits
 * - Campaign ID - 32 bits
 * - Ad Set/Ad Group ID - 32 bits  
 * - Funnel ID - 16 bits
 * - Offer ID - 16 bits
 * - Variant ID (for A/B tests) - 16 bits
 * - Timestamp (minutes since epoch) - 32 bits for uniqueness
 */

import { query } from '../db/query.js';
import * as crypto from 'crypto';

// Base62 character set for short codes (URL-safe)
const BASE62_CHARS = '0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz';

// Platform encoding (2 bits)
const PLATFORM_CODES: Record<string, number> = {
  'facebook': 0,
  'tiktok': 1,
  'google': 2,
  'other': 3
};

const PLATFORM_NAMES: Record<number, string> = {
  0: 'facebook',
  1: 'tiktok',
  2: 'google',
  3: 'other'
};

// UTM source/medium defaults per platform
const PLATFORM_UTM_DEFAULTS: Record<string, { source: string; medium: string }> = {
  'facebook': { source: 'facebook', medium: 'cpc' },
  'tiktok': { source: 'tiktok', medium: 'cpc' },
  'google': { source: 'google', medium: 'cpc' },
  'other': { source: 'direct', medium: 'none' }
};

export interface EncodedUrlParams {
  platform: 'facebook' | 'tiktok' | 'google' | 'other';
  campaignId: string;
  adSetId?: string;
  funnelId?: number;
  offerId?: number;
  variantId?: number;
  testId?: number;
}

export interface DecodedUrlParams extends EncodedUrlParams {
  utmSource: string;
  utmMedium: string;
  utmCampaign: string;
  utmContent?: string;
  utmTerm?: string;
}

export interface ShortUrlResult {
  shortCode: string;
  shortUrl: string;
  originalUrl: string;
  params: EncodedUrlParams;
}

/**
 * Encode a number to Base62 string
 */
function toBase62(num: bigint, minLength: number = 1): string {
  if (num === 0n) return BASE62_CHARS[0].repeat(minLength);

  let result = '';
  while (num > 0n) {
    result = BASE62_CHARS[Number(num % 62n)] + result;
    num = num / 62n;
  }

  while (result.length < minLength) {
    result = BASE62_CHARS[0] + result;
  }

  return result;
}

/**
 * Decode Base62 string to number
 */
function fromBase62(str: string): bigint {
  let result = 0n;
  for (const char of str) {
    const index = BASE62_CHARS.indexOf(char);
    if (index === -1) throw new Error(`Invalid Base62 character: ${char}`);
    result = result * 62n + BigInt(index);
  }
  return result;
}

/**
 * Parse a campaign/adset ID string to a numeric value
 * Handles both numeric IDs and string IDs (hashes string to number)
 */
function parseIdToNumber(id: string | undefined): number {
  if (!id) return 0;

  // If it's already numeric, use it directly
  const num = parseInt(id, 10);
  if (!isNaN(num) && num >= 0) {
    return num >>> 0; // Ensure 32-bit unsigned
  }

  // Hash the string to a number
  let hash = 0;
  for (let i = 0; i < id.length; i++) {
    const char = id.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash = hash >>> 0; // Convert to 32-bit unsigned
  }
  return hash;
}

/**
 * Encode URL parameters into a short code
 * 
 * Bit layout (128 bits total = 22 Base62 chars):
 * - Bits 0-1:    Platform (2 bits)
 * - Bits 2-33:   Campaign ID (32 bits)
 * - Bits 34-65:  Ad Set ID (32 bits)
 * - Bits 66-81:  Funnel ID (16 bits)
 * - Bits 82-97:  Offer ID (16 bits)
 * - Bits 98-113: Variant ID (16 bits)
 * - Bits 114-127: Random/timestamp for uniqueness (14 bits)
 */
export function encodeUrlParams(params: EncodedUrlParams): string {
  const platformCode = PLATFORM_CODES[params.platform] ?? 3;
  const campaignId = parseIdToNumber(params.campaignId);
  const adSetId = parseIdToNumber(params.adSetId);
  const funnelId = (params.funnelId ?? 0) & 0xFFFF;
  const offerId = (params.offerId ?? 0) & 0xFFFF;
  const variantId = (params.variantId ?? 0) & 0xFFFF;

  // Use timestamp + random for uniqueness (14 bits)
  const uniqueness = (Date.now() % 16384) ^ (Math.random() * 16384 | 0);

  // Pack into a 128-bit bigint
  let packed = BigInt(platformCode);
  packed = (packed << 32n) | BigInt(campaignId);
  packed = (packed << 32n) | BigInt(adSetId);
  packed = (packed << 16n) | BigInt(funnelId);
  packed = (packed << 16n) | BigInt(offerId);
  packed = (packed << 16n) | BigInt(variantId);
  packed = (packed << 14n) | BigInt(uniqueness);

  // Convert to Base62 (128 bits = ~22 chars in Base62)
  return toBase62(packed, 11); // 11 chars is enough for our bit layout
}

/**
 * Decode a short code back to URL parameters
 */
export function decodeUrlParams(shortCode: string): DecodedUrlParams {
  const packed = fromBase62(shortCode);

  // Unpack the bits (reverse order of packing)
  // Skip uniqueness bits (14 bits) - they're just for making codes unique
  let remaining = packed >> 14n;

  const variantId = Number(remaining & 0xFFFFn);
  remaining = remaining >> 16n;

  const offerId = Number(remaining & 0xFFFFn);
  remaining = remaining >> 16n;

  const funnelId = Number(remaining & 0xFFFFn);
  remaining = remaining >> 16n;

  const adSetId = Number(remaining & 0xFFFFFFFFn);
  remaining = remaining >> 32n;

  const campaignId = Number(remaining & 0xFFFFFFFFn);
  remaining = remaining >> 32n;

  const platformCode = Number(remaining & 0x3n);
  const platform = (PLATFORM_NAMES[platformCode] ?? 'other') as EncodedUrlParams['platform'];

  const defaults = PLATFORM_UTM_DEFAULTS[platform];

  return {
    platform,
    campaignId: campaignId.toString(),
    adSetId: adSetId > 0 ? adSetId.toString() : undefined,
    funnelId: funnelId > 0 ? funnelId : undefined,
    offerId: offerId > 0 ? offerId : undefined,
    variantId: variantId > 0 ? variantId : undefined,
    utmSource: defaults.source,
    utmMedium: defaults.medium,
    utmCampaign: `campaign_${campaignId}`,
    utmContent: funnelId > 0 ? `funnel_${funnelId}` : undefined,
    utmTerm: offerId > 0 ? `offer_${offerId}` : undefined
  };
}

/**
 * Get the base URL for short URLs
 * Hardcoded to spotlessbinco.com since we never route ad traffic to the api subdomain
 */
function getShortUrlBase(): string {
  return 'https://spotlessbinco.com';
}

/**
 * Get the base landing page URL for a funnel
 */
function getBaseLandingUrl(funnelId?: number): string {
  const baseUrl = getShortUrlBase();
  if (funnelId) {
    return `${baseUrl}/f/${funnelId}`;
  }
  return `${baseUrl}/`;
}

/**
 * Create a short URL that encodes UTM params
 * No database storage needed - params are encoded in the URL itself
 */
export function createEncodedShortUrl(
  baseLandingUrl: string,
  params: EncodedUrlParams
): ShortUrlResult {
  const shortCode = encodeUrlParams(params);
  const baseUrl = getShortUrlBase();

  return {
    shortCode,
    shortUrl: `${baseUrl}/s/${shortCode}`,
    originalUrl: baseLandingUrl,
    params
  };
}

/**
 * Resolve a short code to the full redirect URL with UTM params
 * This is called by the redirect endpoint - no DB lookup needed!
 */
export function resolveEncodedShortUrl(
  shortCode: string,
  baseLandingUrl?: string
): { redirectUrl: string; params: DecodedUrlParams } {
  const params = decodeUrlParams(shortCode);

  // Use provided base URL or construct from funnel ID
  const baseUrl = baseLandingUrl || getBaseLandingUrl(params.funnelId);

  // Build URL with UTM params
  const url = new URL(baseUrl);
  url.searchParams.set('utm_source', params.utmSource);
  url.searchParams.set('utm_medium', params.utmMedium);
  url.searchParams.set('utm_campaign', params.utmCampaign);
  if (params.utmContent) url.searchParams.set('utm_content', params.utmContent);
  if (params.utmTerm) url.searchParams.set('utm_term', params.utmTerm);

  // Add tracking params
  if (params.variantId) url.searchParams.set('variant_id', params.variantId.toString());
  if (params.adSetId) url.searchParams.set('adset_id', params.adSetId);

  return {
    redirectUrl: url.toString(),
    params
  };
}

/**
 * Batch create short URLs for ad permutations
 * Used by bulk ad creation services
 */
export function createEncodedShortUrls(
  permutations: Array<{
    landingUrl: string;
    permutationId: string;
    campaignId?: string;
    adSetId?: string;
    funnelId?: number;
    offerId?: number;
    variantId?: number;
  }>,
  platform: 'facebook' | 'tiktok' | 'google'
): Map<string, ShortUrlResult> {
  const results = new Map<string, ShortUrlResult>();

  for (const p of permutations) {
    const params: EncodedUrlParams = {
      platform,
      campaignId: p.campaignId || '0',
      adSetId: p.adSetId,
      funnelId: p.funnelId,
      offerId: p.offerId,
      variantId: p.variantId
    };

    const result = createEncodedShortUrl(p.landingUrl, params);
    results.set(p.permutationId, result);
  }

  return results;
}

// ============================================================================
// Legacy functions for backwards compatibility (use DB storage)
// These can be deprecated once encoded URLs are proven stable
// ============================================================================

interface ShortenUrlOptions {
  userId?: number;
  expiresAt?: Date;
  metadata?: Record<string, unknown>;
}

interface ShortUrlRecord {
  id: number;
  short_code: string;
  original_url: string;
  created_at: Date;
  expires_at: Date | null;
  click_count: number;
  last_clicked_at: Date | null;
  created_by_user_id: number | null;
  metadata: Record<string, unknown> | null;
}

/**
 * Generate a random Base62 short code (for legacy DB-backed URLs)
 */
function generateRandomShortCode(length: number = 7): string {
  const bytes = crypto.randomBytes(length);
  let code = '';
  for (let i = 0; i < length; i++) {
    code += BASE62_CHARS[bytes[i] % 62];
  }
  return code;
}

/**
 * Legacy: Shorten a URL with database storage
 * @deprecated Use createEncodedShortUrl for ad platform URLs
 */
export async function shortenUrl(
  originalUrl: string,
  options: ShortenUrlOptions = {}
): Promise<{ shortCode: string; shortUrl: string; originalUrl: string }> {
  const { userId, expiresAt, metadata } = options;

  let shortCode: string;
  let attempts = 0;
  const maxAttempts = 5;

  while (attempts < maxAttempts) {
    shortCode = generateRandomShortCode();

    const { rows: existing } = await query<{ id: number }>(
      'SELECT id FROM short_urls WHERE short_code = $1',
      [shortCode]
    );

    if (existing.length === 0) {
      break;
    }

    attempts++;
    if (attempts === maxAttempts) {
      throw new Error('Failed to generate unique short code after maximum attempts');
    }
  }

  const { rows } = await query<ShortUrlRecord>(
    `INSERT INTO short_urls (
      short_code,
      original_url,
      created_by_user_id,
      expires_at,
      metadata
    ) VALUES ($1, $2, $3, $4, $5)
    RETURNING *`,
    [
      shortCode!,
      originalUrl,
      userId || null,
      expiresAt || null,
      metadata ? JSON.stringify(metadata) : null
    ]
  );

  const baseUrl = getShortUrlBase();

  return {
    shortCode: rows[0].short_code,
    shortUrl: `${baseUrl}/s/${rows[0].short_code}`,
    originalUrl: rows[0].original_url
  };
}

/**
 * Legacy: Resolve a DB-backed short URL
 * @deprecated 
 */
export async function resolveShortUrl(shortCode: string): Promise<string | null> {
  const { rows } = await query<ShortUrlRecord>(
    `UPDATE short_urls 
     SET click_count = click_count + 1,
         last_clicked_at = NOW()
     WHERE short_code = $1
       AND (expires_at IS NULL OR expires_at > NOW())
     RETURNING original_url`,
    [shortCode]
  );

  return rows[0]?.original_url || null;
}

// ============================================================================
// Main export for ad platform integration
// ============================================================================

/**
 * Shorten landing URLs for ad permutations
 * Uses encoded URLs (no DB lookup on redirect)
 */
export async function shortenAdLandingUrls(
  permutations: Array<{
    landingUrl: string;
    permutationId: string;
    campaignId?: string;
    adSetId?: string;
    funnelId?: number;
    offerId?: number;
    variantId?: number;
  }>,
  platform: 'facebook' | 'tiktok' | 'google'
): Promise<Map<string, ShortUrlResult>> {
  // Use the encoded URL approach - instant, no DB needed
  return createEncodedShortUrls(permutations, platform);
}

/**
 * Log a click on a short URL (for analytics)
 * Called by the redirect endpoint after resolving the URL
 */
export async function logShortUrlClick(
  shortCode: string,
  _params: DecodedUrlParams, // Params available for future analytics enrichment
  clickInfo: {
    ipAddress?: string;
    userAgent?: string;
    referer?: string;
  }
): Promise<void> {
  try {
    // Store click in url_clicks table for analytics
    await query(
      `INSERT INTO url_clicks (
        short_url_id,
        ip_address,
        user_agent,
        referer
      ) VALUES (
        (SELECT id FROM short_urls WHERE short_code = $1),
        $2::inet,
        $3,
        $4
      )`,
      [
        shortCode,
        clickInfo.ipAddress || null,
        clickInfo.userAgent || null,
        clickInfo.referer || null
      ]
    );
  } catch (error) {
    // Log but don't fail the redirect
    console.error('[url-shortener] Failed to log click:', error);
  }
}

