   if (params.variantId) url.searchParams.set('variant_id', params.variantId.toString());
   if (params.adSetId) url.searchParams.set('adset_id', params.adSetId);
   if (params.zoneId) url.searchParams.set('zone_id', params.zoneId.toString());
