 /**
  * Batch create short URLs for ad permutations
  * Used by bulk ad creation services
  */
 export function createEncodedShortUrls(
   permutations: Array<{
     landingUrl: string;
     permutationId: string;
     campaignId?: string;
     adSetId?: string;
     funnelId?: number;
     offerId?: number;
     variantId?: number;
   }>,
   platform: 'facebook' | 'tiktok' | 'google'
 ): Map<string, ShortUrlResult> {
   const results = new Map<string, ShortUrlResult>();

   for (const p of permutations) {
     const params: EncodedUrlParams = {
       platform,
       campaignId: p.campaignId || '0',
       adSetId: p.adSetId,
       funnelId: p.funnelId,
       offerId: p.offerId,
       variantId: p.variantId
     };

     const result = createEncodedShortUrl(p.landingUrl, params);
